1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	
4	const BASE_PREMIUM: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	  moonstone: 25,
11	};
12	
13	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
14	type QuoteStep = { op: "quote"; items: Item[] };
15	type Step = QuoteStep;
16	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
17	type QuoteResult = { premium: number };
18	type ScenarioResult = { results: QuoteResult[] };
19	
20	const COMPONENT_BLOCK_SIZE = 3;
21	const COMPONENT_BLOCK_PREMIUM = 60;
22	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
23	
24	const itemBasePremium = (item: Item): number => BASE_PREMIUM[item.type];
25	
26	const groupByType = (items: Item[]): Map<string, Item[]> => {
27	  const groups = new Map<string, Item[]>();
28	  for (const item of items) {
29	    const bucket = groups.get(item.type) ?? [];
30	    bucket.push(item);
31	    groups.set(item.type, bucket);
32	  }
33	  return groups;
34	};
35	
36	const groupBasePremium = (type: string, group: Item[]): number => {
37	  if (COMPONENT_TYPES.has(type) && group.length === COMPONENT_BLOCK_SIZE) {
38	    return COMPONENT_BLOCK_PREMIUM;
39	  }
40	  return group.reduce((sum, item) => sum + itemBasePremium(item), 0);
41	};
42	
43	const policyBasePremium = (items: Item[]): number =>
44	  Array.from(groupByType(items).entries()).reduce(
45	    (total, [type, group]) => total + groupBasePremium(type, group),
46	    0,
47	  );
48	
49	const CURSE_SURCHARGE_RATE = 0.5;
50	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
51	const HIGH_ENCHANTMENT_THRESHOLD = 5;
52	const LOYALTY_DISCOUNT_RATE = 0.2;
53	const LOYALTY_YEARS_THRESHOLD = 2;
54	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
55	
56	type Customer = { yearsWithMHPCO: number };
57	
58	const curseSurcharge = (item: Item): number =>
59	  item.cursed ? itemBasePremium(item) * CURSE_SURCHARGE_RATE : 0;
60	
61	const highEnchantmentSurcharge = (item: Item): number =>
62	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
63	    ? itemBasePremium(item) * HIGH_ENCHANTMENT_SURCHARGE_RATE
64	    : 0;
65	
66	const itemSurcharges = (items: Item[]): number =>
67	  items.reduce(
68	    (sum, item) => sum + curseSurcharge(item) + highEnchantmentSurcharge(item),
69	    0,
70	  );
71	
72	const quotePremium = (
73	  items: Item[],
74	  customer: Customer,
75	  isFollowUp: boolean,
76	): number => {
77	  const basePremium = policyBasePremium(items);
78	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
79	  const loyaltyDiscount =
80	    customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD
81	      ? basePremium * LOYALTY_DISCOUNT_RATE
82	      : 0;
83	  const followUpDiscount = isFollowUp ? basePremium * FOLLOW_UP_DISCOUNT_RATE : 0;
84	  return (
85	    basePremium +
86	    itemSurcharges(items) +
87	    firstInsuranceSurcharge -
88	    loyaltyDiscount -
89	    followUpDiscount +
90	    PROCESSING_FEE
91	  );
92	};
93	
94	export const runScenario = (scenario: Scenario): ScenarioResult => {
95	  let quoteCount = 0;
96	  const results = scenario.steps.map((step) => {
97	    const isFollowUp = quoteCount > 0;
98	    quoteCount += 1;
99	    return {
100	      premium: Math.ceil(quotePremium(step.items, scenario.customer, isFollowUp)),
101	    };
102	  });
103	  return { results };
104	};
